import{_ as i,o as a,c,ag as v}from"./chunks/framework.CAXxHpAX.js";const y=JSON.parse('{"title":"曲辕犁、筒车、秧马的作用：节省人力，提高","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-13.md","filePath":"notes/note-13.md"}'),s={name:"notes/note-13.md"};function l(r,d,e,o,t,n){return a(),c("div",null,[...d[0]||(d[0]=[v('<h1 id="曲辕犁、筒车、秧马的作用-节省人力-提高" tabindex="-1">曲辕犁、筒车、秧马的作用：节省人力，提高 <a class="header-anchor" href="#曲辕犁、筒车、秧马的作用-节省人力-提高" aria-label="Permalink to &quot;曲辕犁、筒车、秧马的作用：节省人力，提高&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">曲辕犁、筒车、秧马的作用：</span>节省人力，提高生产效率和生产力，促进农业的精耕细作，有助于经济发展和社会进步。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">清朝对西藏的管理：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>①顺治册封达赖</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>②康熙册封班禅，历代达赖和班禅都需要经过中央政府的册封</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>③驻藏大臣</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>④噶厦</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>⑤《钦定藏内善后章程》</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>⑥金瓶掣签</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>活字印刷术出现，降低了制书成本，加快了图书的普及和文化的传播；</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>火药的使用，改变了欧洲火器制造和作战方式，推动欧洲社会的变革；</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>指南针大大促进世界远洋航海技术的发展，为郑和下西洋和新航路的开辟提供了重要条件。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、南宋和金划定边界：</span>淮水到大散关</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、辽：</span>契丹族、耶律阿保机；西夏：党项族、元昊；金：女真，完颜阿骨打。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>3、宋代农业耕作技术进步的表现是秧马、复种技术</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>4、宋朝为强化中央集权，在中央是怎么做的？分化事权、削弱相权。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、元朝新纳入中央版图的是：</span>西藏（宣政院、宣慰使司都元帅府）、台湾（澎湖巡检司）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、元朝的中央机构有哪三个？行政：</span>中书省 军事：枢密院 监察：御史台</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>2、宋朝海上丝绸之路最远到达哪里？阿拉伯半岛和非洲东海岸</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、辽宋夏金元时期（目录标题）：</span>民族关系发展和社会变化</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、经济中心南移：</span> 唐安史之乱 （开始）—— 南宋 （结束）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、《资治通鉴》朝代：</span>北宋 记述什么时候的历史：战国到五代</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>6、为加强对地方财权的管理，宋太祖怎么做？转运使，把地方财政收归中央</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>7、元朝管理台湾的机构是？澎湖巡检司</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>8、元朝的建立者是？忽必烈 腹里归谁管理？ 中书省（山东、山西、河北）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、宋朝商业发展的特点是：</span>打破了时间、空间限制</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">0、古代经济重心南移的根因是：</span>北人南迁带去劳动力、技术、经验</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、世界上最早的纸币是：</span>交子 朝代：北宋 地区：四川</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>2、为鼓励海外贸易，宋朝在主要港口设立了（市舶司 ）加以管理。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>3、娱乐兼营商业场所是 A瓦子</p></div><div class="circle-overlay"></div></div></div>',34)])])}const x=i(s,[["render",l]]);export{y as __pageData,x as default};
